const items = $input.all().filter(r => r.json.ItemCode);
const companyCode = $env.DP_COMPANY_CODE || 'DEFAULT';
const batchSize = 200;
const batches = [];
const esc = (v) => { if(v===null||v===undefined) return ''; let s=String(v).substring(0,500); s=s.replace(/\0/g,''); return s.replace(/'/g,"''"); };
const cc = esc(companyCode);
for (let i = 0; i < items.length; i += batchSize) {
  const batch = items.slice(i, i + batchSize);
  const values = batch.map(r => {
    const j = r.json;
    return `('${cc}','${esc(j.ItemCode)}','${esc(j.ItemName)}','${esc(j.InvntryUom)}','${esc(j.ManBtchNum)||'N'}',NOW())`;
  }).join(',\n');
  const sql = `INSERT INTO wms.wms_items_cache (company_code, item_code, item_name, uom, man_batch_num, synced_at) VALUES ${values} ON CONFLICT (company_code, item_code) DO UPDATE SET item_name=EXCLUDED.item_name, uom=EXCLUDED.uom, man_batch_num=EXCLUDED.man_batch_num, synced_at=NOW()`;
  batches.push({ json: { sql, count: batch.length } });
}
if (batches.length === 0) return [{ json: { sql: 'SELECT 1', count: 0 } }];
return batches;

const items = $input.all().filter(r => r.json.WhsCode);
const companyCode = $env.DP_COMPANY_CODE || 'DEFAULT';
if (items.length === 0) return [{ json: { sql: 'SELECT 1', count: 0 } }];
const esc = (v) => { if(v===null||v===undefined) return ''; let s=String(v).substring(0,500); s=s.replace(/\0/g,''); return s.replace(/'/g,"''"); };
const cc = esc(companyCode);
const values = items.map(r => {
  const j = r.json;
  return `('${cc}','${esc(j.WhsCode)}','${esc(j.WhsName)}',NOW())`;
}).join(',\n');
const sql = `INSERT INTO wms.wms_locations_cache (company_code, whs_code, whs_name, synced_at) VALUES ${values} ON CONFLICT (company_code, whs_code) DO UPDATE SET whs_name=EXCLUDED.whs_name, synced_at=NOW()`;
return [{ json: { sql, count: items.length } }];

const itemsCount = $('汇总物料').first().json.items_count;
const whsCount = $input.first().json.count || 0;
return { json: { items_count: itemsCount, whs_count: whsCount } };

const items = $input.all().filter(r => r.json.bin_code);
const companyCode = $env.DP_COMPANY_CODE || 'DEFAULT';
const batchSize = 200;
const batches = [];
const esc = (v) => { if(v===null||v===undefined) return ''; let s=String(v).substring(0,500); s=s.replace(/\0/g,''); return s.replace(/'/g,"''"); };
const num = (v) => Number(v)||0;
const cc = esc(companyCode);
for (let i = 0; i < items.length; i += batchSize) {
  const batch = items.slice(i, i + batchSize);
  const values = batch.map(r => {
    const j = r.json;
    return `('${cc}','${esc(j.bin_code)}','${esc(j.whs_code)}','${esc(j.whs_name)}','${esc(j.bin_name)}',${num(j.max_level)},NOW())`;
  }).join(',\n');
  const sql = `INSERT INTO wms.wms_bins_cache (company_code, bin_code, whs_code, whs_name, bin_name, max_level, synced_at) VALUES ${values} ON CONFLICT (company_code, bin_code) DO UPDATE SET whs_code=EXCLUDED.whs_code, whs_name=EXCLUDED.whs_name, bin_name=EXCLUDED.bin_name, max_level=EXCLUDED.max_level, synced_at=NOW()`;
  batches.push({ json: { sql, count: batch.length } });
}
if (batches.length === 0) return [{ json: { sql: 'SELECT 1', count: 0 } }];
return batches;

const prev = $('汇总仓库').first().json;
const binsTotal = $input.all().reduce((s,r)=> s + (r.json.count||0), 0);
return { json: {
  success: true,
  message: `期初灌库完成: 物料 ${prev.items_count} 条, 仓库 ${prev.whs_count} 条, 库位 ${binsTotal} 条`,
  items_count: prev.items_count,
  whs_count: prev.whs_count,
  bins_count: binsTotal
} };
